import novamind_api as nm, json
for gid in ['E1','E2','E3','D_E01','D_E02','D_E03','D_E04','D_E05','D_E06','D_E07','D_E08','D_E09','D_E10']:
    ins=nm.market.get_group_insights(group_id=gid)
    e=ins['estimates']; usage=e.get('usage_volume'); wtp=e.get('willingness_to_pay')
    if usage:
        print(gid, 'wtp',wtp,'usage',usage,'A2cost/mo',round(usage*30*0.002,1),'B3cost',round(usage*30*0.006,1),'C5cost',round(usage*30*0.03,1),'seat_range',e.get('seat_range'))

import novamind_api as nm,json
for gid in ['D_S04','S2','S3','D_S07','D_S02','D_S09','D_S08','E1','E2','E3','D_E02','D_E07','D_E03']:
    print('\n###',gid)
    try:
        ins=nm.market.get_group_insights(group_id=gid)
        print(json.dumps(ins, indent=2)[:5000])
    except Exception as e:
        print('ERR',e)
